"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import StepShell from "@/components/StepShell";
import { getNextStep } from "@/content";
import { triggerShake, getRandomEncourage, getRandomComplete } from "@/lib/learningMessages";

// ===== 比较题数据 =====
const QUESTIONS = [
  { a: 0.8, b: 0.5, answer: "A", label: "0.8 \u548c 0.5 \u8c01\u5927\uff1f" },
  { a: 0.3, b: 0.7, answer: "B", label: "0.3 \u548c 0.7 \u8c01\u5927\uff1f" },
  { a: 1.2, b: 0.9, answer: "A", label: "1.2 \u548c 0.9 \u8c01\u5927\uff1f" },
] as const;

// ===== 数轴参数 =====
const AXIS_MIN = 0;
const AXIS_MAX = 2;
const AXIS_TICKS = 20; // 0, 0.1, 0.2, ... 2.0
const AXIS_WIDTH = 500;
const AXIS_HEIGHT = 120;
const AXIS_PAD = 40;

function valueToX(val: number): number {
  return AXIS_PAD + ((val - AXIS_MIN) / (AXIS_MAX - AXIS_MIN)) * AXIS_WIDTH;
}

const DOT_COLORS = ["var(--accent)", "var(--primary)"];

export default function ComparePage() {
  const [currentQ, setCurrentQ] = useState(0);
  const [selected, setSelected] = useState<string | null>(null);
  const [solved, setSolved] = useState<boolean[]>([false, false, false]);
  const [encourageMsg, setEncourageMsg] = useState("");
  const [completeMsg, setCompleteMsg] = useState("");
  useEffect(() => { setCompleteMsg(getRandomComplete()); }, []);

  const allDone = solved.every(Boolean);
  const q = QUESTIONS[currentQ];

  const handleAnswer = (choice: string) => {
    if (solved[currentQ]) return;
    setSelected(choice);
    if (choice === q.answer) {
      const newSolved = [...solved];
      newSolved[currentQ] = true;
      setSolved(newSolved);
      setEncourageMsg("");
    } else {
      const qEl = document.getElementById("compare-question-box");
      triggerShake(qEl);
      setEncourageMsg(getRandomEncourage());
    }
  };

  const nextStep = getNextStep("decimal", "compare");

  // 数轴上已标记的点
  const markedDots: { val: number; qIdx: number; colorIdx: number }[] = [];
  solved.forEach((done, qIdx) => {
    if (done) {
      markedDots.push({ val: QUESTIONS[qIdx].a, qIdx, colorIdx: 0 });
      markedDots.push({ val: QUESTIONS[qIdx].b, qIdx, colorIdx: 1 });
    }
  });

  return (
    <StepShell topicId="decimal" stepId="compare">
      {/* 数轴区域 */}
      <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
        <p className="mb-4 text-center text-sm text-[var(--text-secondary)]">
          \u770b\u770b\u6570\u8f74\uff0c\u6bd4\u8f83\u5c0f\u6570\u5927\u5c0f
        </p>
        <div className="flex justify-center overflow-x-auto">
          <svg
            viewBox={`0 0 ${AXIS_WIDTH + AXIS_PAD * 2} ${AXIS_HEIGHT}`}
            className="w-full max-w-lg"
          >
            {/* 主轴线 */}
            <line
              x1={AXIS_PAD}
              y1={AXIS_HEIGHT / 2}
              x2={AXIS_PAD + AXIS_WIDTH}
              y2={AXIS_HEIGHT / 2}
              stroke="var(--text-muted)"
              strokeWidth={2}
            />
            {/* 箭头 */}
            <polygon
              points={`${AXIS_PAD + AXIS_WIDTH + 8},${AXIS_HEIGHT / 2} ${AXIS_PAD + AXIS_WIDTH},${AXIS_HEIGHT / 2 - 5} ${AXIS_PAD + AXIS_WIDTH},${AXIS_HEIGHT / 2 + 5}`}
              fill="var(--text-muted)"
            />
            {/* 刻度和标签 */}
            {Array.from({ length: AXIS_TICKS + 1 }).map((_, i) => {
              const val = AXIS_MIN + i * 0.1;
              const x = valueToX(val);
              const isMajor = Number.isInteger(val * 2); // 0, 0.5, 1.0, 1.5, 2.0
              return (
                <g key={i}>
                  <line
                    x1={x}
                    y1={AXIS_HEIGHT / 2 - (isMajor ? 10 : 5)}
                    x2={x}
                    y2={AXIS_HEIGHT / 2 + (isMajor ? 10 : 5)}
                    stroke="var(--text-muted)"
                    strokeWidth={isMajor ? 1.5 : 0.8}
                  />
                  {isMajor && (
                    <text
                      x={x}
                      y={AXIS_HEIGHT / 2 + 24}
                      textAnchor="middle"
                      fill="var(--text-secondary)"
                      fontSize={12}
                    >
                      {val.toFixed(1)}
                    </text>
                  )}
                </g>
              );
            })}
            {/* 已标记的点 */}
            {markedDots.map((dot, i) => (
              <g key={`dot-${i}`}>
                <circle
                  cx={valueToX(dot.val)}
                  cy={AXIS_HEIGHT / 2}
                  r={7}
                  fill={DOT_COLORS[dot.colorIdx]}
                  opacity={0.8}
                />
                <text
                  x={valueToX(dot.val)}
                  y={AXIS_HEIGHT / 2 - 16}
                  textAnchor="middle"
                  fill={DOT_COLORS[dot.colorIdx]}
                  fontSize={11}
                  fontWeight="bold"
                >
                  {dot.val.toFixed(1)}
                </text>
              </g>
            ))}
          </svg>
        </div>
      </div>

      {/* 题目区域 */}
      <div id="compare-question-box" className="mt-6 space-y-4">
        {/* 题目进度 */}
        <div className="flex items-center justify-center gap-2">
          {QUESTIONS.map((_, i) => (
            <div
              key={i}
              className={`h-2.5 w-8 rounded-full transition-all ${
                i === currentQ
                  ? "scale-x-110 bg-[var(--signal-focus)]"
                  : solved[i]
                  ? "bg-[var(--signal-confirmed)]"
                  : "bg-[var(--border)]"
              }`}
              style={{ opacity: solved[i] ? 0.6 : i === currentQ ? 1 : 0.4 }}
            />
          ))}
        </div>

        {/* 当前题目 */}
        {!allDone && (
          <div className="rounded-[var(--radius)] border-2 border-[var(--signal-focus)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-md)]">
            <p className="mb-1 text-center text-sm text-[var(--text-muted)]">
              \u7b2c {currentQ + 1} \u9898
            </p>
            <p className="text-center text-lg font-semibold text-[var(--text)]">
              {q.label}
            </p>
            <div className="mt-4 grid grid-cols-2 gap-3">
              <button
                onClick={() => handleAnswer("A")}
                className={`rounded-lg border px-4 py-3 text-sm font-medium transition-all hover:border-[var(--primary-light)] hover:bg-[var(--signal-focus)]/10 ${
                  selected === "A"
                    ? solved[currentQ]
                      ? "border-[var(--signal-success)] bg-[var(--signal-success)]/10 text-[var(--signal-success)]"
                      : "border-[var(--signal-focus)] bg-[var(--signal-focus)]/10"
                    : "border-[var(--border)] bg-[var(--bg-soft)]"
                }`}
              >
                A. {q.a.toFixed(1)} \u5927
              </button>
              <button
                onClick={() => handleAnswer("B")}
                className={`rounded-lg border px-4 py-3 text-sm font-medium transition-all hover:border-[var(--primary-light)] hover:bg-[var(--signal-focus)]/10 ${
                  selected === "B"
                    ? solved[currentQ]
                      ? "border-[var(--signal-success)] bg-[var(--signal-success)]/10 text-[var(--signal-success)]"
                      : "border-[var(--signal-focus)] bg-[var(--signal-focus)]/10"
                    : "border-[var(--border)] bg-[var(--bg-soft)]"
                }`}
              >
                B. {q.b.toFixed(1)} \u5927
              </button>
            </div>
            {/* 正确反馈 */}
            {solved[currentQ] && (
              <p className="mt-3 text-center text-sm font-medium text-[var(--signal-success)] animate-float-in">
                \u2714 \u5bf9\u4e86\uff01\u5728\u6570\u8f74\u4e0a\u8ddd\u79bb 0 \u8fdc\u7684\u6570\u66f4\u5927\uff01
              </p>
            )}
            {/* 鼓励语 */}
            {encourageMsg && (
              <p className="mt-3 text-center text-sm text-[var(--text-secondary)]">
                \ud83d\udca1 {encourageMsg}
              </p>
            )}
            {/* 下一题 */}
            {solved[currentQ] && currentQ < QUESTIONS.length - 1 && (
              <div className="mt-4 flex justify-center">
                <button
                  onClick={() => {
                    setCurrentQ((p) => p + 1);
                    setSelected(null);
                    setEncourageMsg("");
                  }}
                  className="rounded-full bg-[var(--accent)] px-6 py-3 font-semibold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
                >
                  \u4e0b\u4e00\u9898 \u2192
                </button>
              </div>
            )}
          </div>
        )}
      </div>

      {/* 完成卡片 */}
      {allDone && (
        <div className="mt-6 animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-md)]">
          <div className="text-4xl mb-2">\ud83c\udf1f</div>
          <p className="text-lg font-semibold text-[var(--text)]">
            {completeMsg}
          </p>
          <p className="mt-2 text-sm text-[var(--text-secondary)]">
            \u6bd4\u8f83\u5c0f\u6570\u65f6\uff0c\u770b\u6570\u8f74\u4e0a\u8c01\u5728\u53f3\u8fb9\u5c31\u884c\u5566\uff01
          </p>
          <div className="mt-6 flex justify-center gap-4">
            <button
              onClick={() => {
                setCurrentQ(0);
                setSelected(null);
                setSolved([false, false, false]);
                setEncourageMsg("");
              }}
              className="rounded-full border border-[var(--border)] px-6 py-3 font-medium text-[var(--text-secondary)] transition-all hover:bg-[var(--bg-soft)]"
            >
              \u518d\u7ec3\u4e00\u904d
            </button>
            {nextStep && (
              <Link
                href={nextStep.path}
                className="rounded-full bg-[var(--accent)] px-6 py-3 font-semibold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
              >
                \u4e0b\u4e00\u6b65\uff1a{nextStep.label} \u2192
              </Link>
            )}
          </div>
        </div>
      )}
    </StepShell>
  );
}
